class Solution:
    def maxCount(self, m, n, ops):
        grid = [[0] * n for _ in range(m)]
        for a, b in ops:
            for x in range(a):
                for y in range(b):
                    grid[x][y] += 1
        mx = 0
        for row in grid:
            for v in row:
                if v > mx:
                    mx = v
        return sum(1 for row in grid for v in row if v == mx)

